DOCUMENT();
############################################################ # Load Macros ############################################################ loadMacros( "PGstandard.pl", "PGML.pl", "AnswerFormatHelp.pl", "contextCurrency.pl", "contextPercent.pl", "PGcourse.pl", ); COMMENT('Authored in PreTeXt');
############################################################ # Header ############################################################ TEXT(beginproblem());
############################################################ # PG Setup Code ############################################################ $decimal = random(0.05,0.25,0.01); $item = list_random( 'A bicycle', 'A dishwasher', 'A cell phone', 'A television', 'A car stereo', 'A formal suit', 'A designer dress', 'A tool shed', 'A tablet', 'An annual wine subscription', ); Context("Currency")->flags->set(trimTrailingZeros => 1); $final = 400 + random(-100,100); $current = Currency($final); $solution = $final/(1 - $decimal); $before = Currency($solution); Context("Percent"); $percent = Percent($decimal);
############################################################ # Body ############################################################
BEGIN_PGML [$item] is on sale with a [`[$percent]`] discount and the final price is [`[$current]\text{.}`] What was the original price before the discount is applied?
[_]{$before}{20}
END_PGML
